spec.expr:
(
  count(
    count_over_time(
      {service_name=~"$service_name"}
      | logfmt
      | event_name=~"exception|device.crash|device.anr"
      | keep session_id
      [$__auto]
    )
  )
  /
  count(
    count_over_time(
      {service_name=~"$service_name"}
      | logfmt
      | session_id != ""
      | keep session_id
      [$__auto]
    )
  )
) * 100 or vector(0)
